import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./studentDashboard.css";

const StudentDashboard = () => {
  const navigate = useNavigate();

  /* ---------- AUTH ---------- */
  const token  = localStorage.getItem("token");
  const userId = localStorage.getItem("userId");   // sno
  const role   = localStorage.getItem("role");

  /* ---------- STATE ---------- */
  const [tab, setTab] = useState("overview");
  const [profile, setProfile] = useState({});
  const [mentors, setMentors] = useState([]);
  const [requests, setRequests] = useState([]);
  const [meetings, setMeetings] = useState([]);
  const [reports, setReports] = useState([]);
  const [error, setError] = useState("");

  // Project form
  const [selectedMentor, setSelectedMentor] = useState("");
  const [projTitle, setProjTitle] = useState("");
  const [projDomain, setProjDomain] = useState("");
  const [projDesc, setProjDesc] = useState("");

  // Report upload
  const [reportFile, setReportFile] = useState(null);

  /* ---------- FETCHERS ---------- */
  const api = (path, opts = {}) => fetch(`http://localhost:5050${path}`, {
    ...opts,
    headers: { Authorization: `Bearer ${token}`, ...opts.headers },
  }).then(r => r.json().then(d => ({ ok: r.ok, data: d })));

  const loadProfile = async () => {
    const { ok, data } = await api("/api/students/me");
    if (ok) setProfile(data); else setError(data.error);
  };

  const loadMentors = async () => {
    const { ok, data } = await api("/api/students/mentors");
    if (ok) setMentors(data); else setError(data.error);
  };

  const loadRequests = async () => {
    const { ok, data } = await api(`/api/students/requests/${userId}`);
    if (ok) setRequests(data); else setError(data.error);
  };

  const loadMeetings = async () => {
    const { ok, data } = await api(`/api/students/meetings/${userId}`);
    if (ok) setMeetings(data); else setError(data.error);
  };

  const loadReports = async () => {
    const { ok, data } = await api(`/api/students/reports/${userId}`);
    if (ok) setReports(data); else setError(data.error);
  };

  useEffect(() => {
    if (!token || role !== "student") { navigate("/login"); return; }
    loadProfile(); loadMentors(); loadRequests(); loadMeetings(); loadReports();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [token, role, navigate]);

  /* ---------- ACTIONS ---------- */
  const handleLogout = () => { localStorage.clear(); navigate("/login"); };

  const submitProject = async (e) => {
    e.preventDefault();
    const payload = { mentor_id: selectedMentor, title: projTitle, domain: projDomain, description: projDesc };
    const { ok, data } = await api("/api/students/request", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload),
    });
    if (ok) { setProjTitle(""); setProjDomain(""); setProjDesc(""); loadRequests(); }
    else setError(data.error);
  };

  const uploadReport = async (e) => {
    e.preventDefault();
    if (!reportFile) return;
    const form = new FormData();
    form.append("report", reportFile);
    const res = await fetch(`http://localhost:5050/api/students/reports/upload`, {
      method: "POST",
      headers: { Authorization: `Bearer ${token}` },
      body: form,
    });
    const data = await res.json();
    if (res.ok) { setReportFile(null); loadReports(); }
    else setError(data.error);
  };

  /* ---------- RENDER ---------- */
  return (
    <div className="student-dashboard">
      {/* HEADER */}
      <div className="dashboard-header">
        <h1>Student Dashboard</h1>
        <button className="logout-btn" onClick={handleLogout}>Logout</button>
      </div>

      {/* TABS */}
      <div className="tab-buttons">
        {["overview","mentors","project","meetings","reports"].map(t => (
          <button key={t} className={tab===t?"active":""} onClick={()=>setTab(t)}>
            {t.charAt(0).toUpperCase()+t.slice(1)}
          </button>
        ))}
      </div>

      {error && <p className="error-banner">{error}</p>}

      {/* OVERVIEW */}
      {tab==="overview" && (
        <div className="overview-tab">
          <h2>Welcome, {profile.studentname}!</h2>
          <div className="overview-sections">
            <div className="section-card"><h3>Profile</h3>
              <p><strong>Email:</strong> {profile.Email}</p>
              <p><strong>Semester:</strong> {profile.semester}</p>
              <p><strong>Section:</strong> {profile.section}</p>
            </div>
          </div>
        </div>
      )}

      {/* MENTORS */}
      {tab==="mentors" && (
        <div className="mentors-tab">
          <h2>All Mentors</h2>
          {mentors.length===0 ? <p>No mentors found.</p> :
            <div className="mentors-container">
              {mentors.map(m=>(
                <div key={m.sno} className="mentor-card">
                  <h3>{m.facultyname}</h3>
                  <p><strong>Specialization:</strong> {m.specialization}</p>
                  <p><strong>Email:</strong> {m.Email}</p>
                </div>
              ))}
            </div>
          }
        </div>
      )}

      {/* PROJECT REQUEST */}
      {tab==="project" && (
        <div className="project-tab">
          <h2>Submit Project Idea</h2>
          <form className="project-vertical" onSubmit={submitProject}>
            <label>Mentor</label>
            <select value={selectedMentor} onChange={e=>setSelectedMentor(e.target.value)} required>
              <option value="">-- Select Mentor --</option>
              {mentors.map(m=><option key={m.sno} value={m.sno}>{m.facultyname}</option>)}
            </select>

            <label>Title</label>
            <input value={projTitle} onChange={e=>setProjTitle(e.target.value)} required/>

            <label>Domain</label>
            <input value={projDomain} onChange={e=>setProjDomain(e.target.value)} required/>

            <label>Description</label>
            <textarea value={projDesc} onChange={e=>setProjDesc(e.target.value)} required/>

            <button type="submit">Submit Request</button>
          </form>

          <h2 style={{marginTop:"40px"}}>Your Requests</h2>
          {requests.length===0 ? <p>No requests yet.</p> :
            requests.map(r=>(
              <div key={r.id} className="request-card">
                <h3>{r.project_title}</h3>
                <p><strong>Status:</strong> {r.status}</p>
              </div>
            ))
          }
        </div>
      )}

      {/* MEETINGS */}
      {tab==="meetings" && (
        <div className="meetings-tab">
          <h2>Scheduled Meetings</h2>
          {meetings.length===0 ? <p>No meetings.</p> :
            <table><thead><tr><th>Day</th><th>Time</th><th>Mentor</th></tr></thead>
            <tbody>{meetings.map(m=>(
              <tr key={m.id}><td>{m.day}</td><td>{m.start_time}–{m.end_time}</td><td>{m.facultyname}</td></tr>
            ))}</tbody></table>
          }
        </div>
      )}

      {/* REPORTS */}
      {tab==="reports" && (
        <div className="reports-tab">
          <h2>Upload Progress Report</h2>
          <form onSubmit={uploadReport} className="report-form">
            <input type="file" accept=".pdf,.pptx" onChange={e=>setReportFile(e.target.files[0])} required/>
            <button type="submit">Upload</button>
          </form>

          <h2 style={{marginTop:"30px"}}>Submitted Reports</h2>
          {reports.length===0 ? <p>No reports yet.</p> :
            <ul className="report-list">
              {reports.map(r=><li key={r.id}>{r.filename} – <strong>{r.status}</strong></li>)}
            </ul>
          }
        </div>
      )}
    </div>
  );
};

export default StudentDashboard;
